{
  "mode": "method",
  "tests": [
    {
      "name": "valid_navigation_structure",
      "input": {
        "page": "Privacy Policy"
      },
      "output": {
        "navigation": ["Home", "Challenges", "Privacy Policy", "Contact"]
      },
      "notes": "Validates that the Privacy Policy page has the correct navigation structure."
    },
    {
      "name": "missing_navigation_item",
      "input": {
        "page": "Privacy Policy",
        "navigation": ["Home", "Challenges", "Contact"]
      },
      "output": {
        "error": "Navigation item 'Privacy Policy' is missing."
      },
      "notes": "Tests the scenario where the Privacy Policy is not included in the navigation."
    },
    {
      "name": "empty_navigation",
      "input": {
        "page": "Privacy Policy",
        "navigation": []
      },
      "output": {
        "error": "Navigation cannot be empty."
      },
      "notes": "Checks the handling of an empty navigation array."
    },
    {
      "name": "duplicate_navigation_item",
      "input": {
        "page": "Privacy Policy",
        "navigation": ["Home", "Privacy Policy", "Privacy Policy"]
      },
      "output": {
        "error": "Duplicate navigation item 'Privacy Policy' found."
      },
      "notes": "Validates that duplicate items in navigation are handled correctly."
    },
    {
      "name": "navigation_order",
      "input": {
        "page": "Privacy Policy",
        "navigation": ["Privacy Policy", "Home", "Challenges"]
      },
      "output": {
        "navigation": ["Home", "Challenges", "Privacy Policy"]
      },
      "notes": "Ensures that the navigation order is standardized."
    },
    {
      "name": "nonexistent_page",
      "input": {
        "page": "Nonexistent Page"
      },
      "output": {
        "error": "Page 'Nonexistent Page' does not exist."
      },
      "notes": "Tests the response when a nonexistent page is requested."
    },
    {
      "name": "navigation_with_special_characters",
      "input": {
        "page": "Privacy Policy",
        "navigation": ["Home", "Chall@nges", "Privacy Policy"]
      },
      "output": {
        "navigation": ["Home", "Chall@nges", "Privacy Policy"]
      },
      "notes": "Validates that navigation can handle special characters."
    },
    {
      "name": "long_navigation_items",
      "input": {
        "page": "Privacy Policy",
        "navigation": ["Home", "Challenges", "Privacy Policy with a very long title that exceeds typical lengths"]
      },
      "output": {
        "navigation": ["Home", "Challenges", "Privacy Policy with a very long title that exceeds typical lengths"]
      },
      "notes": "Tests the handling of long navigation item titles."
    }
  ],
  "assumptions": "The navigation structure must always include the Privacy Policy page.",
  "notes": "Ensure that all tests are run in a clean environment to avoid state issues."
}
